-- Ejecutar despues de 01_onboardflow_v0.5.sql.
alter table public.of_candidates add column if not exists group_name text,add column if not exists updated_at timestamptz default now(),add column if not exists updated_by uuid references public.of_profiles(id),add column if not exists deleted_at timestamptz,add column if not exists deleted_by uuid references public.of_profiles(id),add column if not exists deletion_reason text,add column if not exists rejection_reason text,add column if not exists registered_by uuid references public.of_profiles(id);
create table if not exists public.of_former_employees(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.of_tenants(id) on delete cascade,person_id uuid references public.of_people(id),company_name text not null,previous_project text,previous_position text,entry_date date,exit_date date,exit_reason text,eligibility_status text not null default 'review_required' check(eligibility_status in('eligible','review_required','not_eligible')),internal_notes text,reviewed_at timestamptz,updated_by uuid references public.of_profiles(id),created_at timestamptz default now(),updated_at timestamptz default now(),deleted_at timestamptz,deleted_by uuid references public.of_profiles(id),deletion_reason text,unique(tenant_id,company_name,person_id));
create table if not exists public.of_invitations(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.of_tenants(id),session_candidate_id uuid not null references public.of_session_candidates(id),sent_at timestamptz default now(),sent_by uuid not null references public.of_profiles(id),channel text not null,status text not null default 'sent',resend_count integer not null default 0);
alter table public.of_former_employees enable row level security;alter table public.of_invitations enable row level security;
create or replace function public.of_current_role()returns text language sql stable security definer set search_path=public as $$select role from public.of_profiles where id=auth.uid() and active=true limit 1$$;
drop policy if exists "of_candidates_same_tenant" on public.of_candidates;create policy "of_candidates_role_read" on public.of_candidates for select to authenticated using(tenant_id=public.of_current_tenant_id()and(public.of_current_role()in('owner','admin','hr')or(public.of_current_role()='supervisor'and(interviewing_supervisor_id=auth.uid()or registered_by=auth.uid()))));create policy "of_candidates_role_insert" on public.of_candidates for insert to authenticated with check(tenant_id=public.of_current_tenant_id()and public.of_current_role()in('owner','admin','hr','supervisor')and(public.of_current_role()<>'supervisor'or interviewing_supervisor_id=auth.uid()));create policy "of_candidates_hr_update" on public.of_candidates for update to authenticated using(tenant_id=public.of_current_tenant_id()and public.of_current_role()in('owner','admin','hr'))with check(tenant_id=public.of_current_tenant_id());create policy "of_former_hr_all" on public.of_former_employees for all to authenticated using(tenant_id=public.of_current_tenant_id()and public.of_current_role()in('owner','admin','hr'))with check(tenant_id=public.of_current_tenant_id());create policy "of_invitations_role" on public.of_invitations for all to authenticated using(tenant_id=public.of_current_tenant_id()and public.of_current_role()in('owner','admin','hr','supervisor'))with check(tenant_id=public.of_current_tenant_id());
create or replace function public.of_audit_trigger()returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.of_audit_logs(tenant_id,actor_id,entity_type,entity_id,action,details)values(coalesce(new.tenant_id,old.tenant_id),auth.uid(),tg_table_name,coalesce(new.id,old.id),tg_op,jsonb_build_object('before',to_jsonb(old),'after',to_jsonb(new)));return coalesce(new,old);end$$;drop trigger if exists of_candidates_audit on public.of_candidates;create trigger of_candidates_audit after insert or update or delete on public.of_candidates for each row execute function public.of_audit_trigger();drop trigger if exists of_former_audit on public.of_former_employees;create trigger of_former_audit after insert or update or delete on public.of_former_employees for each row execute function public.of_audit_trigger();
